# METHODS THAT DO DATABASE QUERIES #
####################################

def _iterator(self, use_chunked_fetch, chunk_size):
    iterable = self._iterable_class(
        self,
        chunked_fetch=use_chunked_fetch,
        chunk_size=chunk_size or 2000,
    )
    if not self._prefetch_related_lookups or chunk_size is None:
        yield from iterable
        return

    iterator = iter(iterable)
    while results := list(islice(iterator, chunk_size)):
        prefetch_related_objects(results, *self._prefetch_related_lookups)
        yield from results

def iterator(self, chunk_size=None):
    """
    An iterator over the results from applying this QuerySet to the
    database. chunk_size must be provided for QuerySets that prefetch
    related objects. Otherwise, a default chunk_size of 2000 is supplied.
    """
    if chunk_size is None:
        if self._prefetch_related_lookups:
            raise ValueError(
                "chunk_size must be provided when using QuerySet.iterator() after "
                "prefetch_related()."
            )
    elif chunk_size <= 0:
        raise ValueError("Chunk size must be strictly positive.")
    use_chunked_fetch = not connections[self.db].settings_dict.get(
        "DISABLE_SERVER_SIDE_CURSORS"
    )
    return self._iterator(use_chunked_fetch, chunk_size)

async def aiterator(self, chunk_size=2000):
    """
    An asynchronous iterator over the results from applying this QuerySet
    to the database.
    """
    if chunk_size <= 0:
        raise ValueError("Chunk size must be strictly positive.")
    use_chunked_fetch = not connections[self.db].settings_dict.get(
        "DISABLE_SERVER_SIDE_CURSORS"
    )
    iterable = self._iterable_class(
        self, chunked_fetch=use_chunked_fetch, chunk_size=chunk_size
    )
    if self._prefetch_related_lookups:
        results = []

        async for item in iterable:
            results.append(item)
            if len(results) >= chunk_size:
                await aprefetch_related_objects(
                    results, *self._prefetch_related_lookups
                )
                for result in results:
                    yield result
                results.clear()

        if results:
            await aprefetch_related_objects(
                results, *self._prefetch_related_lookups
            )
            for result in results:
                yield result
    else:
        async for item in iterable:
            yield item

def aggregate(self, *args, **kwargs):
    """
    Return a dictionary containing the calculations (aggregation)
    over the current queryset.

    If args is present the expression is passed as a kwarg using
    the Aggregate object's default alias.
    """
    if self.query.distinct_fields:
        raise NotImplementedError("aggregate() + distinct(fields) not implemented.")
    self._validate_values_are_expressions(
        (*args, *kwargs.values()), method_name="aggregate"
    )
    for arg in args:
        # The default_alias property raises TypeError if default_alias
        # can't be set automatically or AttributeError if it isn't an
        # attribute.
        try:
            arg.default_alias
        except (AttributeError, TypeError):
            raise TypeError("Complex aggregates require an alias")
        kwargs[arg.default_alias] = arg

    return self.query.chain().get_aggregation(self.db, kwargs)

async def aaggregate(self, *args, **kwargs):
    return await sync_to_async(self.aggregate)(*args, **kwargs)

def count(self):
    """
    Perform a SELECT COUNT() and return the number of records as an
    integer.

    If the QuerySet is already fully cached, return the length of the
    cached results set to avoid multiple SELECT COUNT(*) calls.
    """
    if self._result_cache is not None:
        return len(self._result_cache)

    return self.query.get_count(using=self.db)

async def acount(self):
    return await sync_to_async(self.count)()

def get(self, *args, **kwargs):
    """
    Perform the query and return a single object matching the given
    keyword arguments.
    """
    if self.query.combinator and (args or kwargs):
        raise NotSupportedError(
            "Calling QuerySet.get(...) with filters after %s() is not "
            "supported." % self.query.combinator
        )
    clone = self._chain() if self.query.combinator else self.filter(*args, **kwargs)
    if self.query.can_filter() and not self.query.distinct_fields:
        clone = clone.order_by()
    limit = None
    if (
        not clone.query.select_for_update
        or connections[clone.db].features.supports_select_for_update_with_limit
    ):
        limit = MAX_GET_RESULTS
        clone.query.set_limits(high=limit)
    num = len(clone)
    if num == 1:
        return clone._result_cache[0]
    if not num:
        raise self.model.DoesNotExist(
            "%s matching query does not exist." % self.model._meta.object_name
        )
    raise self.model.MultipleObjectsReturned(
        "get() returned more than one %s -- it returned %s!"
        % (
            self.model._meta.object_name,
            num if not limit or num < limit else "more than %s" % (limit - 1),
        )
    )

async def aget(self, *args, **kwargs):
    return await sync_to_async(self.get)(*args, **kwargs)

def create(self, **kwargs):
    """
    Create a new object with the given kwargs, saving it to the database
    and returning the created object.
    """
    reverse_one_to_one_fields = frozenset(kwargs).intersection(
        self.model._meta._reverse_one_to_one_field_names
    )
    if reverse_one_to_one_fields:
        raise ValueError(
            "The following fields do not exist in this model: %s"
            % ", ".join(reverse_one_to_one_fields)
        )

    obj = self.model(**kwargs)
    self._for_write = True
    obj.save(force_insert=True, using=self.db)
    obj._state.fetch_mode = self._fetch_mode
    return obj

create.alters_data = True

async def acreate(self, **kwargs):
    return await sync_to_async(self.create)(**kwargs)

acreate.alters_data = True

def _prepare_for_bulk_create(self, objs):
    objs_with_pk, objs_without_pk = [], []
    for obj in objs:
        if isinstance(obj.pk, DatabaseDefault):
            objs_without_pk.append(obj)
        elif obj._is_pk_set():
            objs_with_pk.append(obj)
        else:
            obj.pk = obj._meta.pk.get_pk_value_on_save(obj)
            if obj._is_pk_set():
                objs_with_pk.append(obj)
            else:
                objs_without_pk.append(obj)
        obj._prepare_related_fields_for_save(operation_name="bulk_create")
    return objs_with_pk, objs_without_pk

def _check_bulk_create_options(
    self, ignore_conflicts, update_conflicts, update_fields, unique_fields
):
    if ignore_conflicts and update_conflicts:
        raise ValueError(
            "ignore_conflicts and update_conflicts are mutually exclusive."
        )
    db_features = connections[self.db].features
    if ignore_conflicts:
        if not db_features.supports_ignore_conflicts:
            raise NotSupportedError(
                "This database backend does not support ignoring conflicts."
            )
        return OnConflict.IGNORE
    elif update_conflicts:
        if not db_features.supports_update_conflicts:
            raise NotSupportedError(
                "This database backend does not support updating conflicts."
            )
        if not update_fields:
            raise ValueError(
                "Fields that will be updated when a row insertion fails "
                "on conflicts must be provided."
            )
        if unique_fields and not db_features.supports_update_conflicts_with_target:
            raise NotSupportedError(
                "This database backend does not support updating "
                "conflicts with specifying unique fields that can trigger "
                "the upsert."
            )
        if not unique_fields and db_features.supports_update_conflicts_with_target:
            raise ValueError(
                "Unique fields that can trigger the upsert must be provided."
            )
        # Updating primary keys and non-concrete fields is forbidden.
        if any(not f.concrete for f in update_fields):
            raise ValueError(
                "bulk_create() can only be used with concrete fields in "
                "update_fields."
            )
        if any(f in self.model._meta.pk_fields for f in update_fields):
            raise ValueError(
                "bulk_create() cannot be used with primary keys in "
                "update_fields."
            )
        if unique_fields:
            if any(not f.concrete for f in unique_fields):
                raise ValueError(
                    "bulk_create() can only be used with concrete fields "
                    "in unique_fields."
                )
        return OnConflict.UPDATE
    return None

def bulk_create(
    self,
    objs,
    batch_size=None,
    ignore_conflicts=False,
    update_conflicts=False,
    update_fields=None,
    unique_fields=None,
):
    """
    Insert each of the instances into the database. Do *not* call
    save() on each of the instances, do not send any pre/post_save
    signals, and do not set the primary key attribute if it is an
    autoincrement field (except if
    features.can_return_rows_from_bulk_insert=True).
    Multi-table models are not supported.
    """
    # When you bulk insert you don't get the primary keys back (if it's an
    # autoincrement, except if can_return_rows_from_bulk_insert=True), so
    # you can't insert into the child tables which references this. There
    # are two workarounds:
    # 1) This could be implemented if you didn't have an autoincrement pk
    # 2) You could do it by doing O(n) normal inserts into the parent
    #    tables to get the primary keys back and then doing a single bulk
    #    insert into the childmost table.
    # We currently set the primary keys on the objects when using
    # PostgreSQL via the RETURNING ID clause. It should be possible for
    # Oracle as well, but the semantics for extracting the primary keys is
    # trickier so it's not done yet.

